#!/usr/bin/env python3
"""
Common utilities for workspace janitor.
"""

import os
import sys
import json
import time
import fnmatch
from datetime import datetime, timedelta
from pathlib import Path
import hashlib

WORKSPACE_ROOT = Path(os.environ.get("WORKSPACE", "/home/openclaw/.openclaw/workspace")).resolve()
MEMORY_DIR = WORKSPACE_ROOT / "memory"
JANITOR_LOG = MEMORY_DIR / "janitor_log.md"
CONFIG_PATH = MEMORY_DIR / "janitor_config.json"

# Protected patterns (absolute paths)
PROTECTED_PATTERNS = [
    WORKSPACE_ROOT / "skills",
    WORKSPACE_ROOT / "references",
    WORKSPACE_ROOT / "memory",
    WORKSPACE_ROOT / ".learnings",
    WORKSPACE_ROOT / "AGENTS.md",
    WORKSPACE_ROOT / "TOOLS.md",
    WORKSPACE_ROOT / "USER.md",
    WORKSPACE_ROOT / "HEARTBEAT.md",
    WORKSPACE_ROOT / "SOUL.md",
    WORKSPACE_ROOT / "IDENTITY.md",
]

# Temporary patterns (relative to workspace root)
TEMP_PATTERNS = [
    "*.tmp",
    "temp_*",
    "*_temp",
    "*_backup*",
    "*_old.py",
    "analysis_*.json",
    "temp_process*",
    "temp_*.md",
]

def ensure_memory_dir():
    """Ensure memory directory exists."""
    MEMORY_DIR.mkdir(exist_ok=True)

def load_config():
    """Load janitor configuration, return defaults if missing."""
    defaults = {
        "expiration_days_temporary": 7,
        "expiration_days_project_artifact": 30,
        "expiration_days_skill_artifact": 14,
        "max_file_size_mb": 100,
        "enable_trash": True,
    }
    if CONFIG_PATH.exists():
        try:
            with open(CONFIG_PATH, "r") as f:
                user = json.load(f)
                defaults.update(user)
        except Exception as e:
            log_action("config_load_error", f"Failed to load config: {e}", level="error")
    return defaults

def is_protected(path: Path):
    """Return True if path is in protected zone."""
    abs_path = path.resolve()
    for pat in PROTECTED_PATTERNS:
        if pat.is_dir():
            if abs_path.is_relative_to(pat):
                return True
        else:
            if abs_path == pat:
                return True
    # Also protect any hidden .git or .openclaw directories
    for part in abs_path.parts:
        if part.startswith(".git") or part == ".openclaw":
            return True
    return False

def classify_file(path: Path, rel_path: Path):
    """
    Classify a file into SAFE, SYSTEM, TEMPORARY, PROJECT_ARTIFACT, UNKNOWN.
    Returns tuple (category, risk_level).
    """
    if is_protected(path):
        return "SAFE", "CRITICAL"

    # Check temporary patterns
    name = rel_path.name
    for pat in TEMP_PATTERNS:
        if simple_fnmatch(name, pat):
            return "TEMPORARY", "LOW"

    # Check if inside projects/
    try:
        if rel_path.is_relative_to(Path("projects")):
            return "PROJECT_ARTIFACT", "MEDIUM"
    except ValueError:
        pass

    # Check config-like extensions
    config_exts = {".json", ".yaml", ".yml", ".toml", ".ini", ".cfg", ".conf"}
    if path.suffix in config_exts:
        return "SYSTEM", "LOW"

    return "UNKNOWN", "HIGH"

def simple_fnmatch(name: str, pattern: str):
    """Simple fnmatch for '*' wildcard only."""
    if '*' not in pattern:
        return name == pattern
    parts = pattern.split('*')
    if len(parts) == 2:
        # pattern like "temp_*"
        return name.startswith(parts[0]) and name.endswith(parts[1])
    # fallback to actual fnmatch
    return fnmatch.fnmatch(name, pattern)

def get_file_age_days(path: Path):
    """Return age of file in days based on mtime."""
    mtime = path.stat().st_mtime
    age_seconds = time.time() - mtime
    return age_seconds / (24 * 3600)

def is_expired(path: Path, category: str, config: dict):
    """Determine if file is expired based on category and config."""
    age = get_file_age_days(path)
    if category == "TEMPORARY":
        return age > config["expiration_days_temporary"]
    elif category == "PROJECT_ARTIFACT":
        return age > config["expiration_days_project_artifact"]
    elif category == "SYSTEM" or category == "SAFE":
        return False
    else:  # UNKNOWN
        return False  # never auto-expire

def log_action(action: str, details: str, level: str = "info"):
    """Append an entry to janitor log."""
    ensure_memory_dir()
    timestamp = datetime.utcnow().isoformat() + "Z"
    entry = f"**{timestamp}** [{level.upper()}] {action}: {details}\n"
    with open(JANITOR_LOG, "a") as f:
        f.write(entry)
    print(f"[{level}] {action}: {details}", file=sys.stderr)

def validate_within_workspace(path: Path):
    """Raise ValueError if path is outside workspace."""
    try:
        path.resolve().relative_to(WORKSPACE_ROOT)
    except ValueError:
        raise ValueError(f"Path {path} is outside workspace root {WORKSPACE_ROOT}")

def human_size(size_bytes):
    """Convert bytes to human readable string."""
    for unit in ['B', 'KB', 'MB', 'GB']:
        if size_bytes < 1024.0:
            return f"{size_bytes:.1f} {unit}"
        size_bytes /= 1024.0
    return f"{size_bytes:.1f} TB"

